import"./AppLayout.astro_astro_type_script_index_0_lang.XkQl7kEJ.js";const h=["browser-rpa","scraper","vision","monitor","chat"];fetch("/api/tasks").then(e=>e.json()).then(({tasks:e})=>{h.forEach(n=>{const s=e.filter(t=>t.agent===n),a=s.filter(t=>t.status==="success").length,r=s.length>0?Math.round(a/s.length*100):0,c=document.getElementById(`agent-stats-${n}`);if(c){let t=`<span>${s.length} tugas · ${a} berhasil</span>`;s.length>0&&(t+=`<span class="text-green">${r}% sukses</span>`),c.innerHTML=t}})}).catch(()=>{});
